{
	// Make a wrapping/unwrap request with an invalid token
	resp := testHttpPost(t, root, addr+"/v1/sys/wrapping/unwrap", map[string]interface{}{
		"token": "foo",
	})
	testResponseStatus(t, resp, 400)
	body := map[string][]string{}
	testResponseBody(t, resp, &body)
	if body["errors"][0] != "wrapping token is not valid or does not exist" {
		t.Fatal(body)
	}

	// Check the audit trail on request and response
	if len(noop.ReqAuth) != 1 {
		t.Fatalf("bad: %#v", noop)
	}
	auth := noop.ReqAuth[0]
	if auth.ClientToken != root {
		t.Fatalf("bad client token: %#v", auth)
	}
	if len(noop.Req) != 1 || noop.Req[0].Path != "sys/wrapping/unwrap" {
		t.Fatalf("bad:\ngot:\n%#v", noop.Req[0])
	}

	if len(noop.ReqErrs) != 1 {
		t.Fatalf("bad: %#v", noop.RespErrs)
	}
	if noop.ReqErrs[0] != consts.ErrInvalidWrappingToken {
		t.Fatalf("bad: %#v", noop.ReqErrs)
	}
}

{
	resp := testHttpPostWrapped(t, root, addr+"/v1/auth/token/create", nil, 10*time.Second)
	testResponseStatus(t, resp, 200)
	body := map[string]interface{}{}
	testResponseBody(t, resp, &body)

	wrapToken := body["wrap_info"].(map[string]interface{})["token"].(string)

	// Make a wrapping/unwrap request with an invalid token
	resp = testHttpPost(t, root, addr+"/v1/sys/wrapping/unwrap", map[string]interface{}{
		"token": wrapToken,
	})
	testResponseStatus(t, resp, 200)

	// Check the audit trail on request and response
	if len(noop.ReqAuth) != 3 {
		t.Fatalf("bad: %#v", noop)
	}
	auth := noop.ReqAuth[2]
	if auth.ClientToken != root {
		t.Fatalf("bad client token: %#v", auth)
	}
	if len(noop.Req) != 3 || noop.Req[2].Path != "sys/wrapping/unwrap" {
		t.Fatalf("bad:\ngot:\n%#v", noop.Req[2])
	}

	// Make sure there is only one error in the logs
	if noop.ReqErrs[1] != nil || noop.ReqErrs[2] != nil {
		t.Fatalf("bad: %#v", noop.RespErrs)
	}
}

f, ok := c.auditBackends[entry.Type]
if !ok {
	return nil, fmt.Errorf("unknown backend type: %q", entry.Type)
}
saltConfig := &salt.Config{
	HMAC:     sha256.New,
	HMACType: "hmac-sha256",
	Location: salt.DefaultLocation,
}

be, err := f(ctx, &audit.BackendConfig{
	SaltView:   view,
	SaltConfig: saltConfig,
	Config:     conf,
}, false)
if err != nil {
	return nil, err
}
if be == nil {
	return nil, fmt.Errorf("nil backend returned from %q factory function", entry.Type)
}

auditLogger := c.baseLogger.Named("audit")
c.AddLogger(auditLogger)

switch entry.Type {
case "file":
	key := "audit_file|" + entry.Path

	c.reloadFuncsLock.Lock()

	if auditLogger.IsDebug() {
		auditLogger.Debug("adding reload function", "path", entry.Path)
		if entry.Options != nil {
			auditLogger.Debug("file backend options", "path", entry.Path, "file_path", entry.Options["file_path"])
		}
	}

	c.reloadFuncs[key] = append(c.reloadFuncs[key], func() error {
		if auditLogger.IsInfo() {
			auditLogger.Info("reloading file audit backend", "path", entry.Path)
		}
		return be.Reload(ctx)
	})

	c.reloadFuncsLock.Unlock()
case "socket":
	if auditLogger.IsDebug() {
		if entry.Options != nil {
			auditLogger.Debug("socket backend options", "path", entry.Path, "address", entry.Options["address"], "socket type", entry.Options["socket_type"])
		}
	}
case "syslog":
	if auditLogger.IsDebug() {
		if entry.Options != nil {
			auditLogger.Debug("syslog backend options", "path", entry.Path, "facility", entry.Options["facility"], "tag", entry.Options["tag"])
		}
	}
}

return be, err

